SELECT 
FROM work_order wo
LEFT JOIN project_task t ON t.id = wo.task_id AND t.deleted = 0
LEFT JOIN project p ON p.id = t.project_id AND p.deleted = 0
LEFT JOIN sys_user u ON u.id = wo.engineer_id AND u.deleted = 0

    wo.deleted = 0

        AND (t.task_name LIKE CONCAT('%', #{query.keyword}, '%')
          OR p.project_name LIKE CONCAT('%', #{query.keyword}, '%'))


        AND wo.engineer_id = #{query.engineerId}


        AND wo.task_id = #{query.taskId}


        AND t.project_id = #{query.projectId}


        AND wo.status = #{query.status}


        AND wo.checkin_time >= #{query.checkinStart}


        AND wo.checkin_time < DATE_ADD(#{query.checkinEnd}, INTERVAL 1 DAY)


ORDER BY wo.create_time DESC

SELECT FROM work_order wo LEFT JOIN project_task t ON t.id = wo.task_id AND t.deleted = 0 LEFT JOIN project p ON p.id = t.project_id AND p.deleted = 0 LEFT JOIN sys_user u ON u.id = wo.engineer_id AND u.deleted = 0 WHERE wo.deleted = 0
AND wo.engineer_id = #{engineerId}
AND wo.status = #{status}
ORDER BY wo.create_time DESC
